<# .SYNOPSIS Offline regression for improvement evaluation cards and state transitions. #>
param([switch]$PassThru)
$ErrorActionPreference='Stop';$root=(Resolve-Path(Join-Path $PSScriptRoot '..\..')).Path;$tmp=Join-Path $root '.qianlima\tmp\improvement-pipeline';New-Item -ItemType Directory -Path $tmp -Force|Out-Null;$gate=Join-Path $PSScriptRoot 'invoke-improvement-governance-pipeline.ps1';$hash='c'*64;$validation=[ordered]@{status='passed';candidate_id='candidate-1';candidate_content_sha256=$hash};$vp=Join-Path $tmp 'validation.json';[IO.File]::WriteAllText($vp,($validation|ConvertTo-Json),[Text.UTF8Encoding]::new($false))
function Card($type='model_routing') {[ordered]@{card_id='card-1';candidate_id='candidate-1';candidate_content_sha256=$hash;problem_statement='Improve validated routing quality.';object_type=$type;change_scope=@('route:test');immutable_boundaries=@('no_permission_expansion','no_data_scope_expansion','no_automatic_production_change');baseline_metrics=[ordered]@{quality=.7;latency_ms=100;cost=1};replay_result=[ordered]@{status='passed';report_ref='frozen:replay'};simulation_result=[ordered]@{status='passed';report_ref='simulation:test'};independent_verification=[ordered]@{status='passed';verifier_id='verifier-b';proposer_id='proposer-a';report_ref='verify:test'};canary_scope=[ordered]@{traffic_percent=5;max_tasks=20};rollback_conditions=@('quality_regression','safety_failure');approval=[ordered]@{status='approved';approver='human:owner';approval_ref='approval:1'};effective_version='2.0.0';current_state='evaluated';canary_result=[ordered]@{status='passed';quality_guard_passed=$true;latency_guard_passed=$true;safety_guard_passed=$true;rollback_triggered=$false}}}
function Run($name,$card,$phase,$approval=''){$p=Join-Path $tmp "$name.json";[IO.File]::WriteAllText($p,($card|ConvertTo-Json -Depth 12),[Text.UTF8Encoding]::new($false));$args=@('-EvaluationCardPath',$p,'-CandidateValidationPath',$vp,'-Phase',$phase);if($approval){$args+=@('-HumanApprovalRef',$approval)};$out=& powershell.exe -NoProfile -ExecutionPolicy Bypass -File $gate @args -PassThru 2>&1;[pscustomobject]@{code=$LASTEXITCODE;text=($out-join"`n")}}
$evaluate=Run evaluate (Card) Evaluate;$noApproval=Run no_approval (Card) AuthorizeCanary;$authorized=Run authorized (Card) AuthorizeCanary 'approval:1';$converged=Run converged (Card) ConvergeCanary;$failedCard=Card;$failedCard.canary_result.safety_guard_passed=$false;$rollback=Run rollback $failedCard ConvergeCanary;$permission=Run permission (Card permission) Evaluate;$permissionCanary=Run permission_canary (Card permission) AuthorizeCanary 'approval:1';$self=Card;$self.independent_verification.verifier_id='proposer-a';$selfCheck=Run self_check $self Evaluate
$cases=@([pscustomobject]@{name='evaluation_requires_human_next';passed=($evaluate.code-eq0-and$evaluate.text-match'awaiting_human')},[pscustomobject]@{name='canary_requires_named_human_approval';passed=($noApproval.code-ne0-and$noApproval.text-match'named_human_approval_required')},[pscustomobject]@{name='approved_low_risk_candidate_can_enter_canary';passed=($authorized.code-eq0-and$authorized.text-match'canary_authorized')},[pscustomobject]@{name='passed_canary_creates_release_candidate_only';passed=($converged.code-eq0-and$converged.text-match'release_candidate'-and$converged.text-match'"production_change"\s*:\s*false')},[pscustomobject]@{name='failed_guard_requires_rollback';passed=($rollback.code-eq0-and$rollback.text-match'rollback_required')},[pscustomobject]@{name='permission_change_is_recommendation_only';passed=($permission.code-eq0-and$permission.text-match'recommendation_only')},[pscustomobject]@{name='permission_change_never_enters_canary';passed=($permissionCanary.code-ne0)},[pscustomobject]@{name='self_verification_denied';passed=($selfCheck.code-ne0)});$failed=@($cases|?{-not$_.passed});$r=[pscustomobject]@{passed=($failed.Count-eq0);cases=$cases;production_change=$false;external_calls=$false;permissions_granted=$false};if($PassThru){$r|ConvertTo-Json -Depth 10}else{$cases|Format-Table -AutoSize};if($failed.Count){throw('Improvement governance pipeline regression failed: '+(($failed.name)-join', '))}
